def allow(key, now, bucket):
    # sliding window: drop entries older than 60s, accept if < 10 remain
    bucket[key] = [t for t in bucket.get(key, []) if now - t < 60]
    if len(bucket[key]) < 10:
        bucket[key].append(now)
        return True
    return False


def allow_ip(ip, now, bucket):
    """Per-IP variant of allow(). Takes an IP string and delegates to allow()."""
    if not isinstance(ip, str):
        raise TypeError("ip must be a string")
    return allow(ip, now, bucket)

